323→// createWorktree creates a git worktree using native git command
324→func createWorktree(repoDir, worktreeDir, branch string) error {
325→	cmd := exec.CommandContext(context.Background(), "git", "worktree", "add", worktreeDir, "-b", branch)
326→	cmd.Dir = repoDir
327→	return cmd.Run()
328→}
329→
330→// removeWorktree removes a git worktree using native git command
331→func removeWorktree(repoDir, worktreeDir string) {
332→	cmd := exec.CommandContext(context.Background(), "git", "worktree", "remove", worktreeDir, "--force")
333→	cmd.Dir = repoDir
334→	_ = cmd.Run() //nolint:errcheck // Best effort cleanup, ignore errors
335→}
